INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Bank feed reconciliation$q$, $q$Automatically imports and matches bank transactions to keep the books current with minimal manual entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Online invoicing and payments$q$, $q$Create and send customizable invoices and accept online payment directly from the invoice.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Expense and receipt capture$q$, $q$Photograph or upload receipts to log business expenses on the go.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Cash flow forecasting$q$, $q$Visual forecasting tools project incoming and outgoing cash to help avoid shortfalls.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Financial reporting$q$, $q$Standard profit and loss, balance sheet, and tax-ready reports for owners and accountants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Multi-currency support$q$, $q$Available on higher tiers for invoicing and tracking transactions in foreign currencies.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Inventory tracking$q$, $q$Available on higher tiers to monitor stock levels tied to invoicing and purchasing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Sage ecosystem integration$q$, $q$Connects to Sage Payroll and third-party apps through Sage's app marketplace.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Backed by Sage Group, an established, publicly traded enterprise software vendor with decades of accounting-software experience$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Straightforward invoicing and bank reconciliation suited to sole traders and small businesses$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Tiered pricing lets businesses start cheap and upgrade features as they grow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Wide network of accountants and bookkeepers already familiar with Sage products$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Regional tax and compliance features tuned for markets like the US and UK$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Interface viewed by some reviewers as less modern than newer competitors like Xero or QuickBooks Online$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Fewer built-in third-party integrations than some rivals$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Promotional pricing can make the effective long-term cost unclear until discounts expire$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Advanced ERP-grade functionality requires stepping up to separate Sage Intacct or Sage X3 products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Some useful features, like inventory and multi-currency, are gated behind higher-priced tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$What is Sage Accounting?$q$, $q$Sage Accounting is cloud-based accounting software from Sage Group for sole traders and small businesses, covering invoicing, expense tracking, bank reconciliation, and financial reporting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$How much does Sage Accounting cost?$q$, $q$Pricing is tiered by month, with US list pricing typically starting around 24 dollars per month and promotional rates sometimes as low as 19 dollars per month for new customers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Who makes Sage Accounting?$q$, $q$Sage Accounting is made by Sage Group plc, a British enterprise software company founded in 1981 and headquartered in Newcastle upon Tyne, United Kingdom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Does Sage Accounting integrate with payroll?$q$, $q$Yes, it connects to Sage Payroll and other apps through Sage's Business Cloud ecosystem and app marketplace.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Is Sage Accounting good for freelancers?$q$, $q$Yes, the entry Start tier is aimed at sole traders and freelancers who need basic invoicing and expense tracking.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$What is the difference between Sage Accounting and Sage Intacct?$q$, $q$Sage Accounting is the small-business tier for basic bookkeeping, while Sage Intacct is a separate, more advanced cloud financial management platform aimed at mid-market and enterprise organizations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Does Sage Accounting support multiple currencies?$q$, $q$Multi-currency invoicing and tracking is available on the higher-priced Sage Accounting tiers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Is there a free trial for Sage Accounting?$q$, $q$Sage commonly offers free trial periods or promotional discounted months for new customers, though exact offers vary by region and time.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Freelancer invoicing and expense tracking$q$, $q$Solo freelancers and sole traders use the entry-level plan to send invoices, get paid online, and track deductible expenses.$q$, $q$Freelancers and sole traders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Small business bookkeeping and cash flow management$q$, $q$Small business owners use bank reconciliation, cash flow forecasting, and financial reports to keep day-to-day books current.$q$, $q$Small business owners with a handful of employees$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Bookkeeper and accountant client management$q$, $q$Accounting firms use Sage Accounting's multi-user access and reporting to manage bookkeeping for multiple small-business clients.$q$, $q$Bookkeepers and accounting firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Accounting Start$q$, $q$From around $19 to $24/month$q$, $q$monthly$q$, NULL, $q$["Basic invoicing","Expense tracking","Bank reconciliation","Single user"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Accounting$q$, $q$Around $43/month$q$, $q$monthly$q$, NULL, $q$["Everything in Start","Cash flow forecasting","More detailed reports","Multi-user access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$Accounting Plus$q$, $q$Around $62/month$q$, $q$monthly$q$, NULL, $q$["Everything in Accounting","Inventory management","Multi-currency invoicing","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sage Accounting is the small-business tier of Sage Group's cloud accounting portfolio, sitting below Sage 50cloud and Sage Intacct in the company's product lineup. It targets sole traders, freelancers, and small teams that need straightforward invoicing, expense tracking, and tax-ready reporting without the complexity of a full ERP system.$q$, $q$Sage Group was founded in 1981 in Newcastle upon Tyne and has grown through decades of acquisitions and organic expansion into one of the UK's largest technology companies, giving Sage Accounting the backing of an established, publicly traded enterprise software vendor with a global customer base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform covers the essentials of small-business bookkeeping: bank feed reconciliation, customizable and payable-online invoices, expense and receipt capture, cash flow forecasting, and standard financial reports such as profit and loss and balance sheet statements. Higher tiers add inventory management, multi-currency support, and more advanced reporting.$q$, $q$Sage Accounting also connects into the broader Sage Business Cloud ecosystem, including Sage Payroll, and supports third-party integrations through Sage's app marketplace, letting growing businesses extend the platform rather than switching accounting systems entirely.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4698c6b-f210-42dd-bcc1-bc0d8ae274f3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sage Accounting is sold as a tiered monthly subscription, typically an entry Start plan and one or two higher Accounting and Accounting Plus tiers. US list pricing has started around 24 dollars per month, with promotional offers frequently bringing introductory rates as low as 19 dollars per month for new customers before reverting to standard pricing.$q$, $q$Exact pricing varies by country and active promotion, and Sage regularly runs discounts such as multiple free months for new sign-ups, so buyers should confirm current rates directly on Sage's regional pricing page before purchasing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$GraphQL-first API$q$, $q$Full commerce functionality, from catalog to checkout, exposed through a single GraphQL API for flexible frontend development.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Headless architecture$q$, $q$Decouples the backend from the storefront so developers can build custom frontends in any framework.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Open-source core$q$, $q$Saleor Core is free and BSD-licensed, allowing self-hosting and commercial use without licensing fees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Managed Saleor Cloud$q$, $q$A fully hosted, auto-scaling SaaS version of Saleor with backups for teams that do not want to self-host.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Composable commerce building blocks$q$, $q$Supports products, variants, checkout, orders, payments, and promotions as modular, API-accessible components.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Multi-channel and multi-currency support$q$, $q$Built-in support for selling across multiple sales channels, currencies, and regions from one backend.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Extensibility via apps and webhooks$q$, $q$Developers can extend functionality using Saleor Apps and webhook-based integrations without modifying core code.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Fully open-source core with a permissive BSD license and no self-hosting licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$GraphQL-first API gives developers precise, flexible access to commerce data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Backed by venture funding from known investors including Zalando and Target Global$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Actively maintained with a large GitHub community and real-world adoption by known brands$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Avoids vendor lock-in since the code can be self-hosted and modified$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Headless architecture requires development resources to build a custom storefront rather than an out-of-the-box theme$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Not ideal for non-technical merchants wanting a quick, no-code setup$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Saleor Cloud managed pricing scales with GMV, adding cost as a store grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Self-hosting requires ongoing infrastructure management and Django/Python expertise$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Smaller ecosystem of themes and plugins compared to mainstream platforms like Shopify$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Is Saleor free to use?$q$, $q$Yes, Saleor Core is open source under a BSD license and free to self-host and modify for commercial use. The managed Saleor Cloud service is a separate paid offering.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$What is Saleor Cloud pricing?$q$, $q$Saleor Cloud starts at 159 dollars per month for the Select plan (up to 200,000 dollars in monthly GMV), with a Volume plan at 399 dollars per month for up to 1 million dollars in monthly GMV.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Who founded Saleor?$q$, $q$Saleor was formally founded as a company in 2020 by Mirek Mencel and Patryk Zawadzki, building on an internal project their agency Mirumee Software started in 2013.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Where is Saleor based?$q$, $q$Saleor's engineering team and headquarters are in Wroclaw, Poland, with marketing, sales, and customer success primarily US-based and remote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Is Saleor headless commerce?$q$, $q$Yes, Saleor is a headless, API-first commerce platform that separates the backend from the storefront, exposing functionality through GraphQL.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$What technology is Saleor built on?$q$, $q$Saleor Core is built on Python, Django, and GraphQL.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$What companies use Saleor?$q$, $q$Saleor has been used by brands including Lush and Breitling, among others, per public reporting.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$How much funding has Saleor raised?$q$, $q$Saleor has raised roughly 10 to 11 million dollars, including a 2.5 million dollar seed round from Cherry Ventures and an 8 million dollar round led by Target Global with Zalando participating.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Custom storefront development$q$, $q$Development agencies and in-house engineering teams build fully custom, high-performance storefronts on top of Saleor's GraphQL API.$q$, $q$Developers and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Composable commerce migration$q$, $q$Mid-market and enterprise retailers move off monolithic platforms to a MACH-compliant, API-first commerce backend.$q$, $q$Mid-market and enterprise retail teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Multi-channel and multi-brand retail$q$, $q$Merchants selling across multiple channels, brands, or currencies use Saleor's channel model to manage them from one backend.$q$, $q$Multi-brand and multi-region retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full Saleor Core source code","BSD license for commercial use","Self-managed hosting and infrastructure","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Saleor Cloud Select$q$, $q$$159/month$q$, $q$monthly$q$, NULL, $q$["Managed, auto-scaling hosting","Up to $200,000 in monthly GMV","Automatic backups","No infrastructure management required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$Saleor Cloud Volume$q$, $q$$399/month$q$, $q$monthly$q$, NULL, $q$["Everything in Select","Up to $1,000,000 in monthly GMV","Higher scaling limits","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Saleor is a headless, API-first e-commerce platform built on Python, Django, and GraphQL. Its roots go back to 2013 as an internal project at the Polish agency Mirumee Software, and it was spun out as an independent company, Saleor Commerce, in 2020 by co-founders Mirek Mencel and Patryk Zawadzki, headquartered in Wroclaw, Poland.$q$, $q$The project has become one of the most widely adopted open-source MACH commerce platforms, with over 20,000 GitHub stars and reported use by brands including Lush and Breitling, and the company has raised roughly 10 to 11 million dollars from investors including Cherry Ventures, Target Global, and Zalando.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$As a headless platform, Saleor exposes commerce functionality such as product catalogs, checkout, orders, payments, and promotions through a GraphQL API, letting developers build fully custom storefronts on any frontend framework rather than relying on a fixed theme system.$q$, $q$Saleor Core is fully open source under a BSD license, meaning it can be self-hosted and modified for commercial use at no licensing cost, while Saleor Cloud provides a managed, auto-scaling hosted version for teams that do not want to operate their own infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Saleor Core is free, since the software is open source; costs in that path come from a team's own hosting, infrastructure, and development time rather than from Saleor itself.$q$, $q$For teams that prefer a managed service, Saleor Cloud starts at 159 dollars per month for the Select plan, covering up to 200,000 dollars in monthly gross merchandise value, with a Volume plan at 399 dollars per month for up to 1 million dollars in monthly GMV, and custom enterprise pricing for larger merchants.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fd85391e-2a8c-4713-ae6d-b8babec00fef', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$AI-assisted plan designer$q$, $q$A visual builder with AI assistance for configuring commission plans without custom code or spreadsheets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Real-time commission dashboards$q$, $q$Reps and managers can track earnings, quota attainment, and payout status as deals close.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Manual adjustment tools$q$, $q$Handles exceptions, corrections, and one-off adjustments to commission calculations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Enterprise reporting$q$, $q$Reporting tools for finance and sales operations teams to audit and analyze commission spend.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$CRM and system integrations$q$, $q$Connects to CRM and other business systems to pull deal and payment data automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Multi-currency support$q$, $q$Calculates and displays commissions across multiple currencies for global sales teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Audit logs$q$, $q$Tracks changes to plans and calculations for compliance and dispute resolution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Free first plan configuration$q$, $q$Sales Cookie configures a customer's first commission plan at no charge as part of onboarding.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Transparent, published per-user pricing with no long-term contract required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Free trial and free first-plan configuration lower the barrier to getting started$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Consistent pricing for long-tenured customers since around 2018$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Free year of access for qualifying early-stage startups$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Covers core incentive compensation management needs without enterprise-grade complexity$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Company size and broader corporate information are not widely published$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Higher usage limits and API access require the pricier Business+ tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$May lack the depth of customization larger enterprise incentive compensation suites offer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Per-user pricing can add up for organizations with many payees$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Less brand recognition than larger competitors like Xactly or CaptivateIQ$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$What is Sales Cookie used for?$q$, $q$Sales Cookie automates sales commission and incentive compensation calculations, dashboards, and payout tracking, replacing manual spreadsheet-based processes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$How much does Sales Cookie cost?$q$, $q$The Business plan costs 40 dollars per user per month, and the Business+ plan costs 60 dollars per user per month, both billed on a pay-as-you-go monthly basis.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Is there a free trial for Sales Cookie?$q$, $q$Yes, Sales Cookie offers a 14-day free trial with full feature access using sample demo data and no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Who owns Sales Cookie?$q$, $q$Sales Cookie is operated by Ninth Floor Technologies, headquartered in Bellevue, Washington, United States.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Does Sales Cookie require a long-term contract?$q$, $q$No, Sales Cookie is sold on a pay-as-you-go monthly basis with no long-term commitment required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Does Sales Cookie offer discounts for startups?$q$, $q$Yes, qualifying early-stage technology startups with under 500,000 dollars in annual revenue can use Sales Cookie free for one year.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Does Sales Cookie integrate with CRM systems?$q$, $q$Yes, Sales Cookie connects to CRM and other business systems to automatically pull deal and payment data for commission calculations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$What is the difference between the Business and Business+ plans?$q$, $q$Business+ supports higher volumes (25-plus plans, 100,000-plus transactions), and adds custom authentication, custom integrations, white-labeling, and API access on top of the Business plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Replacing spreadsheet-based commission tracking$q$, $q$Sales operations teams move off manual spreadsheets to automated, auditable commission calculations.$q$, $q$Sales operations and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Multi-plan commission management$q$, $q$Organizations running many concurrent commission plans across teams use Business+ for higher volume and custom configuration.$q$, $q$Mid-market and larger sales organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Startup sales team incentive setup$q$, $q$Early-stage technology startups use the free-for-qualifying-startups offer to stand up commission tracking without upfront cost.$q$, $q$Early-stage startup sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Free Trial$q$, $q$$0/user/month$q$, $q$14-day trial$q$, NULL, $q$["Full feature access","Sample demo data","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Business$q$, $q$$40/user/month$q$, $q$monthly$q$, NULL, $q$["AI-assisted plan designer","Commission dashboards","Adjustments","Team management","Enterprise reports","System and CRM integrations","Multi-currency support","Audit logs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$Business+$q$, $q$$60/user/month$q$, $q$monthly$q$, NULL, $q$["Everything in Business","Supports 25+ plans","100,000+ transactions","Custom authentication","Custom integrations","White labeling","API access","Priority support and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sales Cookie is a commission automation platform operated by Ninth Floor Technologies and headquartered in Bellevue, Washington. It focuses on replacing manual, spreadsheet-based commission tracking with automated calculations, dashboards, and audit trails for sales teams and their managers.$q$, $q$The company markets itself as a fully cloud-based, US-built platform, and has kept consistent per-seat pricing for long-tenured customers since roughly 2018, positioning itself as a straightforward, transparently priced alternative to larger enterprise incentive compensation suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sales Cookie centers on a visual, AI-assisted plan designer for building commission structures, paired with real-time dashboards that let reps and managers track earnings and quota attainment as deals close.$q$, $q$Additional capabilities include manual adjustment workflows, enterprise-grade reporting, multi-currency support, audit logs for compliance, and integrations that pull deal and payment data from CRM and other business systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b12745-37b0-4202-a0e1-39121d42e60e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sales Cookie is sold on a pay-as-you-go, per-user monthly basis with no long-term contract required. The Business plan costs 40 dollars per user per month and covers most core functionality, while Business+ at 60 dollars per user per month adds higher usage limits, custom integrations, white-labeling, and API access.$q$, $q$New customers get a 14-day free trial with full feature access, and every customer's first incentive plan is configured free of charge; qualifying early-stage startups under 500,000 dollars in revenue can use the platform free for a full year.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Unified quote-to-cash workflow$q$, $q$Combines quoting, contracts, e-signature, billing, and payment collection in one self-serve checkout system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Configurable legal terms library$q$, $q$Standardized Master Service Agreements, Commercial Terms, Data Processing Agreements, Service Level Agreements, and Legal Exhibits attachable to deals.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Usage-based and standard billing$q$, $q$Supports both flat and usage-based pricing and billing models common to B2B SaaS.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Full API access$q$, $q$Lets engineering teams programmatically control every part of the revenue workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$CRM and ERP integrations$q$, $q$Connects to CRM, accounting, and other internal systems to keep revenue data in sync.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Self-serve checkout$q$, $q$Enables buyers to review, sign, and pay for contracts without manual sales-ops intervention.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Dedicated support and migration assistance$q$, $q$Growth and Enterprise plans include a dedicated support manager and scoped migration help.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Unifies quoting, contracts, billing, and payments into one platform instead of stitching together multiple tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Purpose-built for B2B SaaS revenue workflows rather than generic enterprise CPQ$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Full API access for engineering-led, programmatic revenue operations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Dedicated support and migration assistance included on Growth and Enterprise plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Backed by venture funding, suggesting ongoing product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Pricing combines subscription fees with transaction-based fees, which can be harder to predict than flat SaaS pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Entry-level Startup plan caps app users at 5$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Full feature set and better rates often require negotiating directly with sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Relatively small team and young company compared to established billing platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Detailed public pricing beyond the three published tiers is limited$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$What does Salesbricks do?$q$, $q$Salesbricks is a quote-to-cash platform for B2B SaaS companies that combines quoting, contracts and e-signature, billing, and payment collection into one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$How much does Salesbricks cost?$q$, $q$The Startup plan is 500 dollars per month billed annually, the Growth plan is 1,500 dollars per month billed annually, and Enterprise pricing is custom, with additional fees tied to invoiced transaction volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$When was Salesbricks founded?$q$, $q$Salesbricks was founded in 2021 by John Louis Swaine and Jon Festejo.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Where is Salesbricks headquartered?$q$, $q$Salesbricks is headquartered in San Mateo, California, United States.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Does Salesbricks charge transaction fees?$q$, $q$Yes, in addition to its tiered subscription plans, Salesbricks charges a fee based on the value of invoices generated through the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Does Salesbricks integrate with CRM systems?$q$, $q$Yes, Salesbricks integrates with CRM, ERP, and accounting systems, with CRM integration included from the Startup plan and CRM plus ERP integration on Enterprise.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$How much funding has Salesbricks raised?$q$, $q$Salesbricks has raised approximately 18.3 million dollars from investors including Surface Ventures and Long Journey Ventures.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Who is Salesbricks best suited for?$q$, $q$Salesbricks is best suited for B2B SaaS companies that want to unify quoting, contracting, billing, and payment collection into a single self-serve checkout system.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$B2B SaaS self-serve checkout$q$, $q$Software companies use Salesbricks to let buyers quote, sign, and pay for subscriptions without manual sales-ops work.$q$, $q$B2B SaaS revenue and sales operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Standardized contract generation$q$, $q$Legal and sales teams use the configurable terms library to generate compliant, standardized contracts quickly.$q$, $q$Legal and deal desk teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Usage-based billing management$q$, $q$SaaS companies with usage-based pricing models use Salesbricks to quote, bill, and collect payment for variable usage.$q$, $q$Usage-based pricing SaaS companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Startup$q$, $q$$500/month$q$, $q$annual$q$, NULL, $q$["Up to 5 app users","Limited reports and analytics","Up to $300k transaction volume","CRM integration","Additional transaction blocks at $500k increments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Growth$q$, $q$$1,500/month$q$, $q$annual$q$, NULL, $q$["Unlimited app users","Full analytics","$300k to $2M transaction volume","CRM integration","Dedicated support manager","Scoped migrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Unlimited app users","Full analytics suite","CRM and ERP integration","Dedicated customer success manager","Migration support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesbricks is a quote-to-cash platform for B2B SaaS companies, founded in 2021 by John Louis Swaine and Jon Festejo and headquartered in San Mateo, California. It combines quoting, contracts, e-signature, billing, and payment collection into a single connected workflow.$q$, $q$The company has raised roughly 18.3 million dollars from investors including Surface Ventures and Long Journey Ventures and operates with a team of around 29 employees, positioning it as a venture-backed, API-first alternative to fragmented quote-to-cash tooling.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Salesbricks provides a configurable library of legal terms, including Master Service Agreements, Commercial Terms, Data Processing Agreements, Service Level Agreements, and Legal Exhibits, that can be attached to deals for standardized, compliant contracts.$q$, $q$The platform also supports usage-based and standard quoting and billing, offers a full API for programmatic control of the revenue workflow, and integrates with CRM, accounting, and other internal systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba708a7-67bb-4103-86f5-6ecb278ba497', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Salesbricks combines tiered monthly subscription pricing with fees tied to the value of invoices processed through the platform. The Startup plan is 500 dollars per month billed annually for up to 5 users and 300,000 dollars in transaction volume, while Growth is 1,500 dollars per month billed annually with unlimited users and up to 2 million dollars in transaction volume.$q$, $q$Larger customers move to a custom-priced Enterprise plan with unlimited users, full analytics, and CRM and ERP integrations; additional transaction capacity beyond each plan's included volume is available in 500,000 dollar increments.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Automated data entry$q$, $q$Captures emails, meetings, and calls automatically from Gmail, Outlook, LinkedIn, and phone without manual logging.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Contact and company enrichment$q$, $q$Enriches contact records using data from email signatures, LinkedIn profiles, and company websites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Native LinkedIn integration$q$, $q$Connects with personal LinkedIn and LinkedIn Sales Navigator via a Chrome extension on every plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Email and link tracking$q$, $q$Tracks email opens and link clicks to signal prospect engagement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Relationship intelligence$q$, $q$Scores relationship strength based on email activity to flag deals needing attention.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Visual pipeline management$q$, $q$Drag-and-drop pipeline views for tracking deals through sales stages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Automated follow-up reminders$q$, $q$Prompts reps to follow up based on tracked activity and inactivity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Zapier and email client integrations$q$, $q$Connects with Gmail, Outlook, and Zapier to fit into existing workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Heavy automation reduces manual CRM data entry for small sales teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Native LinkedIn and Sales Navigator integration included on all plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Relationship intelligence highlights deals at risk based on real activity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Straightforward, transparent per-user pricing with a 30-day free trial$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Lean, product-focused company known for direct customer feedback loops$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Enterprise plan requires a five-user minimum, raising the entry cost for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Smaller ecosystem and brand recognition compared to CRMs like HubSpot or Salesforce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Less configurable for complex, multi-department enterprise sales processes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Email finder lead credits are a separate add-on cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Best suited to email-centric B2B sales motions rather than all industries$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$What is Salesflare used for?$q$, $q$Salesflare is a CRM for small and medium B2B businesses that automates data entry by capturing activity from email, calendar, LinkedIn, and phone.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$How much does Salesflare cost?$q$, $q$Salesflare's Growth plan starts at 29 dollars per user per month billed annually, with Pro at 49 dollars and Enterprise at 99 dollars per user per month annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Who founded Salesflare?$q$, $q$Salesflare was founded in 2014 in Antwerp, Belgium by Jeroen Corthout and Lieven Janssen.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Does Salesflare integrate with LinkedIn?$q$, $q$Yes, Salesflare has native LinkedIn and LinkedIn Sales Navigator integration through a Chrome extension, included on all plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Is there a free trial for Salesflare?$q$, $q$Yes, Salesflare offers a 30-day free trial with no setup fees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Does Salesflare have a minimum user requirement?$q$, $q$Only the Enterprise plan requires a minimum of five users; Growth and Pro plans have no minimum.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Where is Salesflare headquartered?$q$, $q$Salesflare is headquartered in Antwerp, Belgium, with an additional office in New York.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$What makes Salesflare different from other CRMs?$q$, $q$Salesflare emphasizes automated data entry and relationship intelligence, reducing the manual logging typically required in traditional CRMs.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Small B2B sales team pipeline management$q$, $q$Small B2B teams use Salesflare's automated pipeline and activity tracking to manage deals without manual logging.$q$, $q$Small B2B sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$LinkedIn-driven prospecting$q$, $q$Sales reps use the native LinkedIn integration to prospect and sync contact data directly from LinkedIn profiles.$q$, $q$B2B sales reps and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Startup sales operations$q$, $q$Startups adopt Salesflare for a low-maintenance CRM that keeps data current automatically as the team grows.$q$, $q$Startup founders and early sales hires$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Growth$q$, $q$$29/user/month (annual) or $39/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Automated data entry","Email and link tracking","Visual pipeline management","Native LinkedIn integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Pro$q$, $q$$49/user/month (annual) or $64/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Growth","Workflow automation","Deeper reporting","Advanced permissions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Enterprise$q$, $q$$99/user/month (annual) or $124/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Pro","Five-user minimum","Dedicated support","Advanced admin controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesflare is a CRM built for small and medium B2B businesses, founded in 2014 in Antwerp, Belgium by Jeroen Corthout and Lieven Janssen. The company remains headquartered in Antwerp with an additional office in New York, and operates with a lean team of around 30 employees.$q$, $q$Its defining focus is automating CRM data entry, using email, calendar, LinkedIn, and phone activity to automatically build contact timelines and deal histories, reducing the manual logging that causes adoption problems in traditional CRMs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Salesflare automatically captures communication and enriches contact records from email signatures, LinkedIn profiles, and company websites, and includes native LinkedIn and LinkedIn Sales Navigator integration on every plan through a Chrome extension.$q$, $q$Other core features include email and link tracking, automated follow-up reminders, relationship intelligence scoring based on email activity, visual pipeline management, and integrations with Gmail, Outlook, and Zapier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Salesflare offers three per-user pricing tiers with a 30-day free trial and no setup fees: Growth at 29 dollars per user per month billed annually, Pro at 49 dollars per user per month billed annually, and Enterprise at 99 dollars per user per month billed annually with a five-user minimum.$q$, $q$Monthly billing is available at higher rates (39, 64, and 124 dollars per user per month respectively), and optional add-on lead credits can be purchased for the built-in email finder.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Lead and opportunity management$q$, $q$Tracks prospects and deals through customizable sales stages from first contact to close.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Sales forecasting$q$, $q$Provides pipeline visibility and forecasting tools for sales managers and leadership.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Workflow and process automation$q$, $q$Automates repetitive sales tasks, approvals, and follow-ups using built-in automation tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Customizable reporting and dashboards$q$, $q$Configurable reports and dashboards for tracking sales performance and KPIs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Deep platform customization$q$, $q$Built on Salesforce's underlying platform, allowing extensive custom objects, fields, and logic.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$AppExchange marketplace$q$, $q$A large third-party marketplace of apps and integrations that extend Sales Cloud functionality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Territory and API access$q$, $q$Enterprise-tier and above unlock territory management and API access for system integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Agentforce AI agents$q$, $q$Higher tiers include embedded AI agents that can automate sales tasks and generate insights.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Extremely deep customization and scalability suited to complex sales organizations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Massive third-party ecosystem through the AppExchange marketplace$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Wide partner and consulting network for implementation support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Continual investment in AI capabilities through Agentforce$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Integrates natively with the broader Salesforce platform, including Service Cloud, Slack, and Tableau$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Per-user pricing and required add-ons can make total cost significantly higher than lighter CRMs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$All editions except Starter Suite require annual contracts paid upfront$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Implementation and customization often require paid consulting or admin expertise$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Steep learning curve for administrators configuring advanced features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Top-tier AI-inclusive plan, Agentforce 1 Sales, is priced well above competitors' comparable offerings$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$How much does Salesforce Sales Cloud cost?$q$, $q$Sales Cloud pricing runs from 25 dollars per user per month for Starter Suite up to 550 dollars per user per month for the Agentforce 1 Sales edition, with Pro Suite, Enterprise, and Unlimited in between.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$When was Salesforce founded?$q$, $q$Salesforce was founded in 1999 by Marc Benioff, Parker Harris, Dave Moellenhoff, and Frank Dominguez.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Where is Salesforce headquartered?$q$, $q$Salesforce is headquartered in San Francisco, California, United States.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Can I pay for Salesforce monthly?$q$, $q$Only the Starter Suite edition offers monthly billing; all other Sales Cloud editions require an annual contract paid in advance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$How big is Salesforce?$q$, $q$Salesforce employs more than 83,000 people worldwide and reported 41.5 billion dollars in revenue for its 2026 fiscal year.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$What is included in the Starter Suite plan?$q$, $q$Starter Suite bundles basic sales, service, marketing, and commerce tools along with Slack at no extra cost, aimed at small businesses.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$What is Agentforce 1 Sales?$q$, $q$Agentforce 1 Sales is Salesforce's top Sales Cloud edition, bundling the Unlimited feature set with unmetered AI agent usage, Slack Enterprise Plus, Spiff, Sales Planning, and Tableau Next.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Is Salesforce Sales Cloud the same as Salesforce Service Cloud?$q$, $q$No, Sales Cloud focuses on sales pipeline and opportunity management, while Service Cloud is Salesforce's separate product for customer service and support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Enterprise sales pipeline management$q$, $q$Large sales organizations use Sales Cloud to manage complex, multi-stage pipelines across regions and teams.$q$, $q$Enterprise and mid-market sales organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Small business CRM with bundled tools$q$, $q$Small businesses use Starter Suite to get sales, service, and marketing basics plus Slack in one low-cost plan.$q$, $q$Small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Custom sales process automation$q$, $q$Sales operations teams build custom objects, automation, and integrations on top of Sales Cloud's platform for unique processes.$q$, $q$Sales operations and RevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Starter Suite$q$, $q$$25/user/month$q$, $q$monthly or annual$q$, NULL, $q$["All-in-one sales, service, marketing, and commerce tools","Slack included","Basic automation and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Pro Suite$q$, $q$$100/user/month$q$, $q$annual$q$, NULL, $q$["Everything in Starter Suite","More customization","Sales automation","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Enterprise$q$, $q$$175/user/month$q$, $q$annual$q$, NULL, $q$["Advanced automation","Deep customization","Territory management","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Unlimited$q$, $q$$350/user/month$q$, $q$annual$q$, NULL, $q$["Full platform feature set","Premium support","Higher usage limits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$Agentforce 1 Sales$q$, $q$$550/user/month$q$, $q$annual$q$, NULL, $q$["Everything in Unlimited","Unmetered Agentforce AI usage","Slack Enterprise Plus","Spiff","Sales Planning and Programs","Tableau Next"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesforce was founded in 1999 by Marc Benioff, Parker Harris, Dave Moellenhoff, and Frank Dominguez, and is headquartered in San Francisco, California. It pioneered cloud-delivered CRM software and has grown into the world's largest CRM vendor, reporting 41.5 billion dollars in revenue for fiscal year 2026 and employing more than 83,000 people worldwide.$q$, $q$Sales Cloud is Salesforce's flagship product for managing leads, opportunities, pipelines, and sales forecasting, and forms the foundation of a much broader platform that now includes Service Cloud, Marketing Cloud, Slack, Tableau, and the Agentforce AI layer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sales Cloud provides lead and opportunity management, customizable pipelines, sales forecasting, workflow automation, and reporting and dashboards, with deep customization available through its underlying platform (formerly known as Lightning Platform or Force.com).$q$, $q$Higher tiers add territory management, advanced automation, API access for integrations, and increasingly, embedded generative AI through Salesforce's Agentforce agents, which can automate tasks like lead qualification, follow-ups, and forecasting analysis.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d43ee8f4-1247-4fdd-8035-fef66e1db0b3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sales Cloud is priced per user per month across five editions: Starter Suite at 25 dollars, Pro Suite at 100 dollars, Enterprise at 175 dollars, Unlimited at 350 dollars, and Agentforce 1 Sales at 550 dollars, the last four billed annually.$q$, $q$Starter Suite is the only edition offering monthly billing; all other editions require an annual contract paid in advance, and add-ons such as additional Agentforce credits, extra storage, or premium support can increase the effective per-user cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Case management$q$, $q$Tracks, prioritizes, and resolves customer support cases from creation to closure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Omnichannel routing$q$, $q$Automatically routes incoming inquiries across email, chat, phone, and social to the best-qualified available agent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Service console$q$, $q$A unified agent workspace for handling cases, knowledge articles, and customer context in one screen.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Knowledge base$q$, $q$Self-service and agent-assisted knowledge articles to speed up resolution and enable customer self-help.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Einstein Bots$q$, $q$AI-powered conversational bots that automate routine customer service interactions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$AI case classification and reply recommendations$q$, $q$Einstein AI automatically classifies incoming cases and suggests responses to speed up agent handling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Service Cloud Voice (add-on)$q$, $q$Telephony integration that brings phone channel data into the same console as other service channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Field Service (add-on)$q$, $q$Dispatch and mobile workforce management for organizations handling on-site service visits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unifies customer service data with Salesforce CRM and Sales Cloud data on one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Strong omnichannel routing and case management for complex support organizations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Deep AI investment through Einstein and Einstein 1 Service with a dedicated trust and compliance layer$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Highly configurable service console and workflow automation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Backed by Salesforce's large partner, consulting, and AppExchange ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Add-on modules like Voice, Field Service, and Digital Engagement significantly increase real-world cost beyond base list pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$All editions except Starter Suite require annual contracts paid upfront$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Implementation and configuration often require paid Salesforce consulting expertise$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Pricing at the Enterprise and above tiers is considerably higher than dedicated help desk tools like Zendesk or Freshdesk$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Steep learning curve for administrators managing complex omnichannel and AI configurations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$How much does Salesforce Service Cloud cost?$q$, $q$Service Cloud pricing runs from 25 dollars per user per month for Starter Suite up to 500 dollars per user per month for the Einstein 1 Service edition, with Pro Suite, Enterprise, and Unlimited in between.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$When did Salesforce Service Cloud launch?$q$, $q$Service Cloud launched in 2009 as Salesforce's dedicated customer service and case management platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$What is Einstein 1 Service?$q$, $q$Einstein 1 Service is Service Cloud's top tier, bundling the Unlimited feature set with embedded generative AI, unmetered AI usage, and Data Cloud capabilities, priced at 500 dollars per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Does Service Cloud include phone support?$q$, $q$Basic channels are included in core Service Cloud, but full telephony integration requires the separately priced Service Cloud Voice add-on.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Is Service Cloud the same as Sales Cloud?$q$, $q$No, Service Cloud is Salesforce's separate product for customer support and case management, while Sales Cloud focuses on sales pipeline and opportunity management, though both share the same underlying Salesforce platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Can I pay for Service Cloud monthly?$q$, $q$Only the Starter Suite edition offers monthly billing; all higher editions require an annual contract paid in advance.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$What AI features does Service Cloud include?$q$, $q$Service Cloud includes Einstein Bots, automated case classification, and AI-generated reply recommendations, running on the Einstein Trust Layer for data protection and compliance.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Who makes Salesforce Service Cloud?$q$, $q$Service Cloud is made by Salesforce, Inc., founded in 1999 and headquartered in San Francisco, California.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Omnichannel customer support$q$, $q$Support organizations use Service Cloud to route and manage cases consistently across email, chat, phone, and social channels.$q$, $q$Customer support and contact center teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unified sales and service data$q$, $q$Companies already using Sales Cloud adopt Service Cloud to keep sales and support data unified on one CRM platform.$q$, $q$Organizations running both sales and support on Salesforce$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$AI-assisted case resolution$q$, $q$Support teams use Einstein Bots and AI reply recommendations to speed up case resolution and deflect routine inquiries.$q$, $q$Enterprise support teams adopting AI-assisted service$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Starter Suite$q$, $q$$25/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Case management","Email-to-case","Basic knowledge base","Basic omnichannel"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Pro Suite$q$, $q$$100/user/month$q$, $q$annual$q$, NULL, $q$["Everything in Starter Suite","Advanced case automation","Macros","Service console customization"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Enterprise$q$, $q$$165/user/month$q$, $q$annual$q$, NULL, $q$["Omnichannel routing","Full service console","Advanced workflow automation","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unlimited$q$, $q$$330/user/month$q$, $q$annual$q$, NULL, $q$["Full feature set","Premium 24/7 support","Higher usage limits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Einstein 1 Service$q$, $q$$500/user/month$q$, $q$annual$q$, NULL, $q$["Everything in Unlimited","Embedded generative AI (Einstein)","Data Cloud access","Unmetered AI credits"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesforce Service Cloud is the customer service and support product of Salesforce, Inc., founded in 1999 and headquartered in San Francisco, California. Service Cloud itself launched in 2009 as Salesforce's dedicated platform for case management and support automation, sitting alongside Sales Cloud within the broader Salesforce ecosystem.$q$, $q$The product has been significantly expanded with AI, starting with Einstein in 2016 and generative AI through Einstein GPT in 2023, and today ranges from a 25 dollar per user per month Starter Suite up to a 500 dollar per user per month Einstein 1 Service tier with embedded generative AI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core Service Cloud functionality centers on case management, omnichannel routing that directs inquiries to the best-available agent across channels, a knowledge base for self-service, and a unified service console workspace for agents.$q$, $q$Its Einstein AI layer adds Einstein Bots, automated case classification, and AI-generated reply recommendations, all governed by the Einstein Trust Layer to help keep sensitive data out of third-party LLMs and support GDPR and CCPA compliance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Service Cloud is priced per user per month across five editions: Starter Suite at 25 dollars, Pro Suite at 100 dollars, Enterprise at 165 dollars, Unlimited at 330 dollars, and Einstein 1 Service at 500 dollars, with only Starter Suite available on monthly billing.$q$, $q$Add-on modules such as Digital Engagement, Service Cloud Voice, Field Service, and expanded Knowledge Base functionality are priced separately, often adding 50 to 200 dollars per user per month, so a fully equipped contact center typically costs more than the base list price.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Unlimited email accounts$q$, $q$Connect multiple sending email accounts without per-inbox fees on most plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Automated multi-step sequences$q$, $q$Build cold email sequences with conditional logic and automated follow-ups.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Email warmup$q$, $q$Gradually builds sender reputation to improve inbox placement and deliverability.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Built-in email finder and verifier$q$, $q$Finds and verifies prospect email addresses directly within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Personalization at scale$q$, $q$Merge fields and dynamic content to personalize outreach across large prospect lists.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$A/B testing$q$, $q$Tests subject lines and email copy to optimize open and reply rates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Deliverability monitoring$q$, $q$Tools to track and protect sender reputation across high-volume sending.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Campaign analytics$q$, $q$Dashboards tracking open, reply, click, and bounce rates across campaigns.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Bundles email sequencing, warmup, deliverability, and lead finding into one subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Unlimited email account connections on most plans reduces per-inbox costs$q$, 1);
