INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Annual billing offers meaningfully lower rates than monthly billing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Sending limits scale with price, so high-volume senders can face significant cost at the top tiers$q$, 0);
