INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Focused specifically on cold email rather than being a full CRM or multichannel sales platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Advanced AI automation and premium support are reserved for the top Scale Plus tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Company size and financials are less publicly documented than larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$What is Saleshandy used for?$q$, $q$Saleshandy is a cold email outreach platform used to run automated email sequences, find and verify prospect emails, and manage sender deliverability.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$How much does Saleshandy cost?$q$, $q$Saleshandy's Outreach plans range from 25 dollars per month for Starter up to 209 dollars per month for Scale Plus on annual billing, with higher rates on monthly billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$When was Saleshandy founded?$q$, $q$Saleshandy was founded in 2015.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Where is Saleshandy headquartered?$q$, $q$Saleshandy is headquartered in Ahmedabad, Gujarat, India, with an additional US presence registered in Newark, Delaware.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Does Saleshandy include email finding?$q$, $q$Yes, Saleshandy includes a built-in email finder and verifier for building prospect lists.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$How many emails can I send on Saleshandy's Starter plan?$q$, $q$The Outreach Starter plan supports sending up to 6,000 emails per month.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Does Saleshandy offer email warmup?$q$, $q$Yes, Saleshandy includes email warmup tools to protect sender reputation and improve inbox placement.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Is Saleshandy a full CRM?$q$, $q$No, Saleshandy is focused specifically on cold email outreach and lead generation rather than being a full CRM.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Cold email outreach campaigns$q$, $q$Sales teams use Saleshandy to build and automate multi-step cold email sequences to prospects.$q$, $q$Sales development reps and outbound sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Agency client prospecting$q$, $q$Agencies run outreach campaigns on behalf of clients using Saleshandy's sequencing and deliverability tools.$q$, $q$Marketing and sales agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Recruiter candidate sourcing$q$, $q$Recruiters use email finding and sequencing to reach out to candidates at scale.$q$, $q$Recruiters and talent sourcing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Outreach Starter$q$, $q$$25/month$q$, $q$annual$q$, NULL, $q$["Up to 6,000 emails/month","Unlimited email accounts","Sequences","Email warmup"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Outreach Pro$q$, $q$$69/month$q$, $q$annual$q$, NULL, $q$["Up to 100,000 emails/month","Enhanced personalization","A/B testing","Advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Outreach Scale$q$, $q$$139/month$q$, $q$annual$q$, NULL, $q$["Higher sending volume","Deliverability tools","Advanced sequencing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$Outreach Scale Plus$q$, $q$$209/month (annual) or $299/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 300,000 emails/month","AI-powered automation","Premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Saleshandy is a cold email outreach platform founded in 2015 and headquartered in Ahmedabad, Gujarat, India, with an estimated 50 to 100 employees and a US presence registered in Newark, Delaware. It serves sales teams, agencies, and recruiters running high-volume outbound email campaigns.$q$, $q$The company reports being used by more than 25,000 businesses, agencies, and sales teams worldwide, and centers its product on combining email sequencing, deliverability, and prospect data finding in one subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include unlimited email account connections, automated multi-step sequences with conditional logic, email warmup to protect sender reputation, and a built-in email finder and verifier for building prospect lists.$q$, $q$Higher tiers add enhanced personalization, A/B testing of subject lines and copy, deliverability tooling, AI-powered automation, and analytics dashboards for tracking open, reply, and bounce rates.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76fff3bb-4eec-44a2-9bbd-0790b17495c7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Saleshandy is priced on sending volume across four Outreach tiers billed annually: Starter at 25 dollars per month (up to 6,000 emails/month), Pro at 69 dollars per month (up to 100,000 emails/month), Scale at 139 dollars per month, and Scale Plus at 209 dollars per month (up to 300,000 emails/month).$q$, $q$Monthly billing is available at higher rates, with Scale Plus costing 299 dollars per user per month when billed monthly instead of annually.$q$]::text[], 2);
