-- ── Saleor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, GraphQL-first headless commerce platform for developers building custom storefronts, available self-hosted or as the managed Saleor Cloud SaaS.$q$, short_description),
  pricing_model = COALESCE($q$Open-core: free open-source self-hosted core, plus paid managed Saleor Cloud subscription tiers$q$, pricing_model),
  starting_price = COALESCE($q$$159/month (Saleor Cloud Select plan)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Wroclaw, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Saleor Review 2026: Pricing, Features and Open-Source Commerce$q$, seo_title),
  seo_meta_description = COALESCE($q$Saleor pricing, features, and open-source model explained. Compare self-hosted Saleor Core with managed Saleor Cloud plans for headless commerce.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Saleor is an open-source, GraphQL-first headless commerce platform built for developers who want full control over the storefront layer while relying on a composable, API-driven backend for products, checkout, orders, and payments. The technology traces back to 2013 as an internal e-commerce project of the Polish web agency Mirumee Software, and was formally spun out as its own startup, Saleor Commerce, in 2020 by co-founders Mirek Mencel and Patryk Zawadzki. The company's engineering team is based in Wroclaw, Poland, which serves as its headquarters, while marketing, sales, and customer success functions are primarily US-based and remote. Saleor Core, the open-source engine, is built on Python, Django, and GraphQL, is licensed under a BSD license that permits commercial use without licensing fees, and has attracted over 20,000 stars on GitHub, making it one of the most widely adopted open-source MACH (microservices, API-first, cloud-native, headless) commerce platforms. Notable brands reported to use Saleor include Lush and Breitling. Saleor has raised a total of roughly 10 to 11 million dollars in venture funding, including a 2.5 million dollar seed round from Berlin-based Cherry Ventures and an 8 million dollar seed-extension round led by Target Global with participation from e-commerce company Zalando, announced in February 2024. Commercially, Saleor follows an open-core model: businesses can self-host Saleor Core entirely for free, or pay for Saleor Cloud, the company's fully managed SaaS offering aimed at mid-to-large merchants that need automatic scaling, backups, and hosted infrastructure without operating Saleor themselves. Saleor Cloud pricing starts at 159 dollars per month for the Select plan, which includes up to 200,000 dollars in monthly gross merchandise value before additional usage fees apply, scaling up to a Volume plan at 399 dollars per month covering up to 1 million dollars in monthly GMV, with custom enterprise pricing above that. Because Saleor is headless, it separates the commerce backend from the customer-facing frontend, so merchants and agencies typically pair it with a separate frontend framework such as Next.js and build or customize a storefront rather than getting an out-of-the-box theme, which distinguishes it from monolithic platforms like Shopify or WooCommerce. This makes Saleor best suited to development teams and agencies building custom, high-performance storefronts or composable commerce stacks rather than non-technical merchants wanting a quick, no-code setup.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fd85391e-2a8c-4713-ae6d-b8babec00fef';

