-- ── Sales Cookie ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based sales commission and incentive compensation management software for automating commission calculations, plan design, and payout reporting.$q$, short_description),
  pricing_model = COALESCE($q$Per-user, pay-as-you-go monthly subscription$q$, pricing_model),
  starting_price = COALESCE($q$$40/user/month (Business plan)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Bellevue, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sales Cookie Review 2026: Pricing, Features and Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Sales Cookie pricing, features, and plans for sales commission automation. See how this incentive compensation management tool works and what it costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sales Cookie is a cloud-based sales commission and incentive compensation management platform designed to help small and mid-sized businesses automate the calculation, tracking, and payout of sales commissions without relying on error-prone spreadsheets. The product is operated by Ninth Floor Technologies and is headquartered in Bellevue, Washington, in the United States; the company describes itself as 100 percent cloud-based and 100 percent built in the USA. Public materials indicate the platform has maintained the same per-seat pricing for existing customers for roughly eight years as of 2026, with customers who signed up around 2018 still paying that original rate, which places its market launch in approximately 2018. Sales Cookie is sold on a pay-as-you-go, per-user monthly subscription with no long-term contracts and no setup fees; a 'user' in its pricing model covers both commission-earning payees and plan administrators. The entry point is a 14-day free trial with full feature access using sample demo data and no credit card required. Paid tiers include a Business plan at 40 dollars per user per month, the most commonly selected option, which includes AI-assisted plan configuration, a visual plan designer, real-time commission dashboards for reps and managers, manual adjustment tools, team management, enterprise-grade reporting, integrations with CRM and other business systems, multi-currency support, and audit logs. A higher Business+ tier at 60 dollars per user per month is aimed at more demanding organizations, supporting 25 or more concurrent commission plans, over 100,000 transactions, and over 1,000 calculations, and adds custom authentication, custom integrations, white-labeling, API access, and priority support and onboarding. Sales Cookie also offers free plan configuration for a customer's first incentive plan regardless of tier, and extends a full year of free access to qualifying early-stage technology startups with under 500,000 dollars in annual revenue. The platform is positioned to replace manual commission tracking in spreadsheets for sales organizations of varying sizes, competing in the incentive compensation management category alongside tools such as CaptivateIQ, Xactly, and QuotaPath. Because it emphasizes transparent, published per-user pricing, no long-term commitment, and free onboarding for the first commission plan, Sales Cookie is frequently positioned toward small and mid-market sales teams that want to move off spreadsheets quickly without a lengthy procurement or implementation process, distinguishing it from more enterprise-oriented incentive compensation platforms that require custom sales-led pricing and longer deployment timelines.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a5b12745-37b0-4202-a0e1-39121d42e60e';

