-- ── Salesforce ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$The world's leading CRM platform, anchored by Sales Cloud, used to manage leads, opportunities, pipelines, and sales automation for companies of any size.$q$, short_description),
  pricing_model = COALESCE($q$Tiered per-user monthly or annual subscription$q$, pricing_model),
  starting_price = COALESCE($q$$25/user/month (Starter Suite)$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE($q$83,000+ employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Salesforce Review 2026: Sales Cloud Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Salesforce Sales Cloud pricing, plans, and features for 2026, from the 25 dollar Starter Suite to the Agentforce 1 Sales tier. See what each edition includes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Salesforce is the customer relationship management platform founded in 1999 by Marc Benioff, Parker Harris, Dave Moellenhoff, and Frank Dominguez, and headquartered in San Francisco, California. It pioneered the software-as-a-service delivery model for enterprise applications and has grown into the world's largest CRM provider by market share, reporting 41.5 billion dollars in revenue for its 2026 fiscal year, up 10 percent year over year, and employing more than 83,000 people globally as a publicly traded company (NYSE: CRM). Sales Cloud is Salesforce's original and best-known product, providing lead and opportunity management, pipeline and forecasting tools, workflow automation, and reporting for sales teams, and today it spans five main pricing editions. Starter Suite costs 25 dollars per user per month and is the only edition available on monthly billing, bundling basic sales, service, marketing, and commerce tools along with Slack at no extra cost, aimed at small businesses. Pro Suite steps up to 100 dollars per user per month, adding deeper customization, sales automation, and reporting for growing teams. Enterprise, at 175 dollars per user per month, is where most mid-market sales organizations land, unlocking advanced automation, territory management, and the API access needed for deeper systems integration. Unlimited, at 350 dollars per user per month, adds the full platform feature set along with premium support and higher usage limits. The top tier, Agentforce 1 Sales, costs 550 dollars per user per month billed annually and bundles the Unlimited feature set with Salesforce's full AI agent suite, unmetered employee Agentforce usage, Slack Enterprise Plus, Spiff incentive compensation, Sales Planning, Sales Programs, Maps, Tableau Next, and org-level AI credits. With the exception of Starter Suite, all Sales Cloud editions are sold on annual contracts paid in advance rather than month-to-month. Salesforce's broader platform extends well beyond Sales Cloud into products such as Service Cloud for customer support, Marketing Cloud, Commerce Cloud, Slack, Tableau, MuleSoft, and the Data Cloud and Agentforce AI layer that now underpins many of its newer offerings. The company is known for a vast partner and consulting ecosystem, an extensive AppExchange marketplace of third-party integrations, and its annual Dreamforce conference. Because of its depth of customization and scalability, Salesforce Sales Cloud is most commonly chosen by mid-market and enterprise sales organizations that need extensive configurability, though its per-user pricing and add-on costs can make it considerably more expensive than lighter-weight CRMs aimed at small businesses.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd43ee8f4-1247-4fdd-8035-fef66e1db0b3';

