-- ── Salesforce Service Cloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Salesforce's customer service and support platform, unifying case management, omnichannel routing, and AI-driven agent tools for support teams.$q$, short_description),
  pricing_model = COALESCE($q$Tiered per-user monthly or annual subscription$q$, pricing_model),
  starting_price = COALESCE($q$$25/user/month (Starter Suite)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$83,000+ employees (Salesforce, Inc.)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Salesforce Service Cloud Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Salesforce Service Cloud pricing, plans, and features for 2026, from the 25 dollar Starter Suite to the 500 dollar Einstein 1 Service tier.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Salesforce Service Cloud is the customer service and support product line of Salesforce, Inc., the CRM company founded in 1999 by Marc Benioff, Parker Harris, Dave Moellenhoff, and Frank Dominguez, and headquartered in San Francisco, California, with more than 83,000 employees worldwide as of its fiscal 2026 reporting. While Salesforce itself dates to 1999, Service Cloud as a distinct product was launched in 2009 to bring case management and customer support automation into the same platform as Sales Cloud, and it has since been substantially expanded with AI capabilities, most notably through Einstein, which Salesforce introduced at its Dreamforce conference in September 2016 and later extended with generative AI through Einstein GPT in 2023. Service Cloud is built around case management, omnichannel routing that sends incoming customer inquiries to the most qualified available agent across channels like email, chat, phone, and social, a knowledge base for self-service and agent-assisted resolution, and a service console that gives agents a unified workspace for handling cases. Its Einstein AI layer adds Einstein Bots for automated conversational support, automatic case classification, and AI-generated reply recommendations, all running on Salesforce's Einstein Trust Layer, which is designed to keep sensitive customer data from being stored inside third-party large language models and to support GDPR and CCPA compliance. Service Cloud is priced per user per month across the same five-tier structure as Sales Cloud: Starter Suite at 25 dollars, Pro Suite at 100 dollars, Enterprise at 165 dollars, Unlimited at 330 dollars, and the top AI-inclusive tier, Einstein 1 Service, at 500 dollars. As with Sales Cloud, Starter Suite is the only edition available on monthly billing; every other tier is sold as a twelve-month annual commitment. Service Cloud carries some of the heaviest optional add-on costs in the Salesforce portfolio, since capabilities like Digital Engagement (messaging channels), Service Cloud Voice (telephony integration), Field Service (dispatch and mobile workforce management), and expanded Knowledge Base functionality are each priced separately, typically adding 50 to 200 dollars per user per month on top of the base edition. Because of this modular add-on structure, real-world Service Cloud costs for a fully equipped contact center are often considerably higher than the base per-user list price suggests. Service Cloud is commonly evaluated against dedicated help desk and support platforms such as Zendesk, Freshdesk, and Intercom, and is most often chosen by organizations that already use or plan to use Salesforce Sales Cloud and want unified sales and service data on one CRM platform rather than a standalone support tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50' AND logo IS NULL AND website IS NOT NULL;

DELETE FROM tool_features WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_pros WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_cons WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_faqs WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_use_cases WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_pricing_plans WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';

DELETE FROM tool_content_blocks WHERE tool_id = 'ad6b4961-5c42-461f-8aa7-a80fba6f7c50';


-- ── Saleshandy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cold email outreach and lead generation platform for sales teams, agencies, and recruiters, offering sequences, deliverability tools, and email finding.$q$, short_description),
  pricing_model = COALESCE($q$Tiered monthly or annual subscription based on email sending volume$q$, pricing_model),
  starting_price = COALESCE($q$$25/month (Outreach Starter plan, annual billing)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$50-100 employees$q$, company_size),
  headquarters = COALESCE($q$Ahmedabad, Gujarat, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Saleshandy Review 2026: Pricing, Features and Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Saleshandy pricing, features, and plans for 2026. See how this cold email outreach and lead generation platform works and what each tier costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Saleshandy is a cold email outreach and lead generation platform used by sales teams, agencies, and recruiters to run multi-step email sequences, find and verify prospect email addresses, and manage sender deliverability at scale. The company was founded in 2015 and is headquartered in Ahmedabad, Gujarat, India, operating as a private SaaS company with an estimated 50 to 100 employees and an additional US-registered presence in Newark, Delaware. Saleshandy states it is trusted by more than 25,000 businesses, agencies, and sales teams worldwide. The platform's core capabilities include unlimited email account connections, automated multi-step sequences with conditional logic, email warmup tools to protect sender reputation and inbox placement, a built-in email finder and verifier for building prospect lists, personalization at scale, A/B testing of subject lines and copy, and analytics dashboards for tracking open, reply, and bounce rates across campaigns. Saleshandy is sold on a tiered monthly subscription model based primarily on sending volume, with all published tiers offering a lower rate on annual billing versus monthly billing. The Outreach Starter plan costs 25 dollars per month on annual billing and supports sending up to 6,000 emails per month, aimed at freelancers, startups, and small businesses just beginning cold outreach. The Outreach Pro plan costs 69 dollars per month on annual billing and raises the sending limit to 100,000 emails per month while adding enhanced personalization and A/B testing, aimed at scaling teams and sales professionals. The Outreach Scale plan costs 139 dollars per month on annual billing with higher sending volume and deliverability tooling. The top published tier, Outreach Scale Plus, costs 209 dollars per month on annual billing (or 299 dollars per user per month on monthly billing) and supports up to 300,000 emails per month with AI-powered automation and premium support, targeted at large-scale operations, agencies, and enterprises. Because Saleshandy centers specifically on cold email deliverability and sequencing rather than being a full CRM, it is most commonly compared against other cold outreach tools such as Instantly, Smartlead, Lemlist, and Woodpecker rather than against general-purpose sales engagement platforms. Its combination of unlimited email accounts even on lower tiers, built-in lead-finding data, and warmup tooling positions it as a cost-conscious option for teams running high-volume outbound email campaigns who want deliverability and prospecting bundled into one subscription rather than paid separately.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76fff3bb-4eec-44a2-9bbd-0790b17495c7';

